using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.Diagnostics;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        // Breaking change: Sync I/O now throws by default.
        // Suppress until all call sites are migrated to async.
        optionsBuilder.ConfigureWarnings(w => w.Ignore(CosmosEventId.SyncNotSupported));
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Breaking change: discriminator property renamed from "Discriminator" to "$type".
            // Preserve legacy name so existing documents and raw SQL
            // (e.g. SELECT VALUE c FROM c WHERE c.Discriminator = 'Blog') keep working.
            b.HasDiscriminator<string>("Discriminator");

            // Breaking change: JSON "id" no longer includes the discriminator.
            // Existing documents use the "Blog|1" format — preserve it.
            b.HasDiscriminatorInJsonId();

            // Breaking change: key property now maps directly to JSON "id",
            // eliminating the shadow "__id" property. Existing documents store
            // the key under a separate JSON property — preserve shadow id.
            b.HasShadowId();

            // Breaking change: HasIndex now throws on the Cosmos provider.
            // Removed — Cosmos indexes all properties by default.
            // (was: b.HasIndex(b => b.Name);)
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

